// 解析 Alertmanager Webhook 数据
const body = $input.first().json;
const alerts = body.alerts || [];

// 只处理 firing 状态的告警
const firingAlerts = alerts.filter(a => a.status === 'firing');

if (firingAlerts.length === 0) {
  console.log('No firing alerts, skipping...');
  return [];
}

// 取第一条告警处理（实际可扩展为并发处理多条）
const alert = firingAlerts[0];
const labels = alert.labels || {};
const annotations = alert.annotations || {};

return [{
  json: {
    alert_name: labels.alertname,
    severity: labels.severity,
    status: alert.status,
    fired_at: alert.startsAt,
    namespace: labels.namespace || 'default',
    pod_name: labels.pod || '',
    container_name: labels.container || '',
    deployment_name: labels.deployment || labels.pod?.replace(/-[a-z0-9]{5}-[a-z0-9]{5}$/, '') || '',
    summary: annotations.summary || '',
    description: annotations.description || '',
    action_hint: labels.action_type || '',
    labels: labels,
    raw_alert: alert
  }
}];

// 构建发送给 LLM 的 Prompt
const alertData = $('解析告警数据').first().json;
const promData = $input.first().json;

// 解析 Prometheus 返回的指标
let cpuUsagePct = 'N/A';
try {
  const result = promData.data?.result?.[0]?.value?.[1];
  if (result) cpuUsagePct = (parseFloat(result) * 100).toFixed(1) + '%';
} catch(e) {}

const userMessage = `
请根据以下 Kubernetes 集群告警信息，输出标准化的 JSON 修复方案。

## 告警详情
- 告警名称: ${alertData.alert_name}
- 告警级别: ${alertData.severity}
- 触发时间: ${alertData.fired_at}
- 命名空间: ${alertData.namespace}
- Pod: ${alertData.pod_name}
- Deployment: ${alertData.deployment_name}

## 告警描述
${alertData.summary}
${alertData.description}

## 实时指标
- CPU 使用率: ${cpuUsagePct}
- 预期操作类型(参考): ${alertData.action_hint}

请严格按 JSON schema 输出分析结论和修复方案。
`;

return [{
  json: {
    ...alertData,
    cpu_usage: cpuUsagePct,
    llm_user_message: userMessage
  }
}];

