// 解析 LLM 返回的 JSON 修复方案
const llmResponse = $input.first().json;
const alertData = $('构建 LLM Prompt').first().json;

let healingPlan;
try {
  // 从 LLM 响应中提取 JSON
  const content = llmResponse.output?.choices?.[0]?.message?.content ||
                  llmResponse.choices?.[0]?.message?.content || '';

  // 尝试直接解析 JSON
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    healingPlan = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in LLM response');
  }
} catch(e) {
  console.error('LLM response parse error:', e.message);
  // 降级：发送人工告警
  healingPlan = {
    analysis: 'LLM响应解析失败，需要人工介入',
    confidence: 0,
    action: 'investigate',
    risk_level: 'high',
    human_approval_required: true,
    notify: true,
    summary_for_notification: `🔴 [KubeSentinel] 告警 ${alertData.alert_name} 需要人工处理（AI决策失败）`
  };
}

return [{
  json: {
    ...alertData,
    healing_plan: healingPlan,
    should_auto_execute: healingPlan.confidence > 0.75 && !healingPlan.human_approval_required && healingPlan.action !== 'no_action' && healingPlan.action !== 'investigate'
  }
}];

